import { ethers } from "ethers";
import fetch from "node-fetch";

const BASE_URL = process.env.HYPERLIQUID_TESTNET
  ? "https://api.hyperliquid-testnet.xyz"
  : "https://api.hyperliquid.xyz";

const PRIVATE_KEY = process.env.HYPERLIQUID_PRIVATE_KEY;
const ADDRESS = process.env.HYPERLIQUID_ADDRESS;

function getAddress() {
  if (PRIVATE_KEY) {
    const wallet = new ethers.Wallet(PRIVATE_KEY);
    return wallet.address;
  }
  if (ADDRESS) return ADDRESS;
  throw new Error(
    "Address required: set HYPERLIQUID_ADDRESS or HYPERLIQUID_PRIVATE_KEY"
  );
}

async function infoRequest(body) {
  const res = await fetch(`${BASE_URL}/info`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  return res.json();
}

async function getBalance() {
  const address = getAddress();
  const data = await infoRequest({
    type: "clearinghouseState",
    user: address,
  });

  const summary = data.crossMarginSummary;
  return {
    address,
    accountValue: summary.accountValue,
    totalMarginUsed: summary.totalMarginUsed,
    availableBalance: (
      parseFloat(summary.accountValue) - parseFloat(summary.totalMarginUsed)
    ).toFixed(2),
  };
}

async function getPositions() {
  const address = getAddress();
  const data = await infoRequest({
    type: "clearinghouseState",
    user: address,
  });

  return data.assetPositions
    .filter((p) => parseFloat(p.position.szi) !== 0)
    .map((p) => ({
      coin: p.position.coin,
      size: p.position.szi,
      entryPrice: p.position.entryPx,
      positionValue: p.position.positionValue,
      unrealizedPnl: p.position.unrealizedPnl,
      leverage: p.position.leverage,
    }));
}

async function getOrders() {
  const address = getAddress();
  return infoRequest({ type: "openOrders", user: address });
}

async function getFills() {
  const address = getAddress();
  return infoRequest({ type: "userFills", user: address });
}

async function getPrice(coin) {
  const mids = await infoRequest({ type: "allMids" });
  if (!mids[coin]) throw new Error(`Unknown coin: ${coin}`);
  return { coin, price: mids[coin] };
}

async function getMeta() {
  return infoRequest({ type: "meta" });
}

async function signAction(wallet, action) {
  const timestamp = Date.now();
  const message = JSON.stringify({ action, timestamp });
  const signature = await wallet.signMessage(message);
  return { action, signature, timestamp };
}

async function placeOrder(coin, isBuy, price, size) {
  if (!PRIVATE_KEY) throw new Error("Private key required for trading");
  const wallet = new ethers.Wallet(PRIVATE_KEY);

  const meta = await getMeta();
  const assetIndex = meta.universe.findIndex((a) => a.name === coin);
  if (assetIndex === -1) throw new Error(`Unknown coin: ${coin}`);

  const action = {
    type: "order",
    orders: [
      {
        a: assetIndex,
        b: isBuy,
        p: price.toString(),
        s: size.toString(),
        r: false,
        t: { limit: { tif: "Gtc" } },
      },
    ],
    grouping: "na",
  };

  const signed = await signAction(wallet, action);
  const res = await fetch(`${BASE_URL}/exchange`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(signed),
  });
  return res.json();
}

async function marketOrder(coin, isBuy, size) {
  const priceData = await getPrice(coin);
  const currentPrice = parseFloat(priceData.price);
  const slippage = isBuy ? 1.05 : 0.95;
  const limitPrice = (currentPrice * slippage).toFixed(2);
  return placeOrder(coin, isBuy, limitPrice, size);
}

async function cancelOrder(coin, orderId) {
  if (!PRIVATE_KEY) throw new Error("Private key required for trading");
  const wallet = new ethers.Wallet(PRIVATE_KEY);

  const meta = await getMeta();
  const assetIndex = meta.universe.findIndex((a) => a.name === coin);
  if (assetIndex === -1) throw new Error(`Unknown coin: ${coin}`);

  const action = {
    type: "cancel",
    cancels: [{ a: assetIndex, o: orderId }],
  };

  const signed = await signAction(wallet, action);
  const res = await fetch(`${BASE_URL}/exchange`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(signed),
  });
  return res.json();
}

async function cancelAllOrders(coin) {
  if (!PRIVATE_KEY) throw new Error("Private key required for trading");
  const wallet = new ethers.Wallet(PRIVATE_KEY);

  let cancels = [];
  if (coin) {
    const meta = await getMeta();
    const assetIndex = meta.universe.findIndex((a) => a.name === coin);
    if (assetIndex === -1) throw new Error(`Unknown coin: ${coin}`);
    const orders = await getOrders();
    cancels = orders
      .filter((o) => o.coin === coin)
      .map((o) => ({ a: assetIndex, o: o.oid }));
  }

  const action = { type: "cancel", cancels };
  const signed = await signAction(wallet, action);
