// Step 1: Get asset index for ETH
const metaRes = await fetch(`${BASE_URL}/info`, {
  method: "POST",
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify({ type: "meta" }),
});
const meta = await metaRes.json();
const universe = meta.universe;
const ethIndex = universe.findIndex((a) => a.name === "ETH");
if (ethIndex === -1) {
  console.error("ETH not found in universe");
  process.exit(1);
}
console.log(`ETH asset index: ${ethIndex}`);

// Step 2: Build the updateLeverage action
const timestamp = Date.now();
const action = {
  type: "updateLeverage",
  asset: ethIndex,
  isCross: true,   // true = cross margin, false = isolated
  leverage: 3,
};

// Step 3: Sign the action
// Hyperliquid signing: sign the action hash
const actionStr = JSON.stringify(action);

// Hyperliquid uses a specific signing scheme
// The message to sign is: keccak256(abi.encode(action, nonce, vaultAddress))
// For simplicity, use the phantom agent signing approach

const phantomAgent = {
  source: "a",
  connectionId: ethers.keccak256(
    ethers.toUtf8Bytes(JSON.stringify({ action, nonce: timestamp, vaultAddress: null }))
  ),
};

// Hyperliquid signing domain
const domain = {
  name: "Exchange",
  version: "1",
  chainId: 1337,
  verifyingContract: "0x0000000000000000000000000000000000000000",
};

const types = {
  Agent: [
    { name: "source", type: "string" },
    { name: "connectionId", type: "bytes32" },
  ],
};

const signature = await wallet.signTypedData(domain, types, phantomAgent);
const { r, s, v } = ethers.Signature.from(signature);

// Step 4: Send the request
const payload = {
  action,
  nonce: timestamp,
  signature: { r, s, v },
  vaultAddress: null,
};

console.log("\nSending updateLeverage request...");
const res = await fetch(`${BASE_URL}/exchange`, {
  method: "POST",
  headers: { "Content-Type": "application/json" },
  body: JSON.stringify(payload),
});

const result = await res.json();
console.log("\nResponse:", JSON.stringify(result, null, 2));

if (result.status === "ok") {
  console.log("\n✅ Successfully updated ETH leverage to 3x (cross margin)");
} else {
  console.error("\n❌ Failed to update leverage:", result);
}
